"""Загрузка плагинов из файлов и каталогов."""from __future__ import annotationsimport importlib.utilimport loggingimport sysfrom dataclasses import dataclass, fieldfrom pathlib import Pathfrom types import ModuleTypefrom typing import Any, Iterablefrom ..core.interfaces import IFilter, ISignalfrom ..core.registry import Registry, RegistryErrorfrom .validator import PluginError, PluginImportError, validate_module_log = logging.getLogger("safr.plugins")_module_counter = 0@dataclass(frozen=True)class LoadedPlugin:    path: Path    plugin: Any    kind: str    name: str@dataclass(frozen=True)class LoadError:    path: Path    error_type: str    message: str@dataclass(frozen=True)class LoadReport:    loaded: list[LoadedPlugin] = field(default_factory=list)    errors: list[LoadError] = field(default_factory=list)    @property    def success_count(self) -> int:        return len(self.loaded)    @property    def error_count(self) -> int:        return len(self.errors)    def extend(self, other: "LoadReport") -> "LoadReport":        return LoadReport(            loaded=[*self.loaded, *other.loaded],            errors=[*self.errors, *other.errors],        )def _import_module_from_path(path: Path) -> ModuleType:    global _module_counter    _module_counter += 1    safe_name = f"safr_user_plugin_{_module_counter}_{path.stem}"    try:        spec = importlib.util.spec_from_file_location(safe_name, path)        if spec is None or spec.loader is None:            raise PluginImportError(f"Не удалось создать spec для '{path}'")        module = importlib.util.module_from_spec(spec)        sys.modules[safe_name] = module        try:            spec.loader.exec_module(module)        except Exception as e:            sys.modules.pop(safe_name, None)            raise PluginImportError(                f"Ошибка при импорте '{path.name}': {type(e).__name__}: {e}"            ) from e        return module    except PluginImportError:        raise    except Exception as e:        raise PluginImportError(            f"Ошибка при импорте '{path}': {type(e).__name__}: {e}"        ) from edef _classify(plugin: Any) -> str:    if isinstance(plugin, ISignal):        return "signal"    if isinstance(plugin, IFilter):        return "filter"    raise PluginError(f"Неизвестный тип плагина: {type(plugin).__name__}")def load_plugin_file(path: str | Path) -> LoadReport:    path = Path(path)    report = LoadReport()    if not path.is_file() or path.suffix != ".py":        report.errors.append(LoadError(            path=path,            error_type="FileNotFoundError" if not path.exists() else "ValueError",            message=f"Ожидается существующий .py-файл, получено: {path}",        ))        return report    try:        module = _import_module_from_path(path)    except PluginError as e:        _log.warning("plugin import failed: %s", e)        report.errors.append(LoadError(            path=path, error_type=type(e).__name__, message=str(e),        ))        return report    try:        plugin = validate_module(module)        kind = _classify(plugin)    except PluginError as e:        _log.warning("plugin validation failed: %s", e)        report.errors.append(LoadError(            path=path, error_type=type(e).__name__, message=str(e),        ))        return report    report.loaded.append(LoadedPlugin(        path=path, plugin=plugin, kind=kind, name=plugin.name,    ))    _log.info("plugin loaded: %s (%s) from %s", plugin.name, kind, path.name)    return reportdef load_plugins_from_dir(directory: str | Path,                          recursive: bool = False) -> LoadReport:    directory = Path(directory)    report = LoadReport()    if not directory.is_dir():        report.errors.append(LoadError(            path=directory,            error_type="NotADirectoryError",            message=f"Каталог не найден: {directory}",        ))        return report    files = (sorted(p for p in directory.rglob("*.py") if p.is_file())             if recursive else             sorted(p for p in directory.glob("*.py") if p.is_file()))    for f in files:        if f.name.startswith("_"):            continue        report = report.extend(load_plugin_file(f))    return reportdef register_loaded(loaded: Iterable[LoadedPlugin],                    registry: Registry) -> LoadReport:    report = LoadReport()    for lp in loaded:        try:            if lp.kind == "signal":                registry.register_signal(lp.plugin)            elif lp.kind == "filter":                registry.register_filter(lp.plugin)            else:                raise PluginError(f"Unknown kind: {lp.kind!r}")        except RegistryError as e:            _log.warning("plugin registration conflict: %s", e)            report.errors.append(LoadError(                path=lp.path,                error_type="RegistryError",                message=f"Имя '{lp.name}' уже зарегистрировано как {lp.kind}: {e}",            ))            continue        except PluginError as e:            report.errors.append(LoadError(                path=lp.path, error_type=type(e).__name__, message=str(e),            ))            continue        report.loaded.append(lp)    return report